IOT_QUESTIONS_PART9 = [{'question': 'A hospital deploys connected infusion pumps that communicate patient medication dosing data to the nursing station. A security researcher reports a vulnerability allowing remote modification of dosing parameters. What is the immediate response priority?', 'options': [{'text': 'Issue a press release acknowledging the vulnerability before taking any technical action to maintain transparency', 'explanation': 'Public disclosure before implementing protective measures would give attackers a roadmap to exploit the vulnerability before hospitals can protect patients. Patient safety must be the immediate priority before any public communications.', 'correct': False}, {'text': 'Immediately isolate infusion pumps from network access implement manual monitoring protocols notify clinical staff and coordinate with the FDA and manufacturer on emergency remediation', 'explanation': 'Correct. Patient safety is the immediate priority. Network isolation prevents remote exploitation, manual monitoring maintains patient safety without network connectivity, clinical staff need to know about the risk and monitoring requirements, and coordinating with FDA and manufacturer initiates the regulatory and technical remediation process. This follows the patient safety first principle for medical device cybersecurity.', 'correct': True}, {'text': 'Wait for the manufacturer to release a patch before taking any action to avoid disrupting clinical operations', 'explanation': 'Waiting for a patch while a critical patient safety vulnerability is known and unmitigated is inappropriate. Immediate network isolation provides protection while the patch is developed.', 'correct': False}, {'text': 'Replace all infusion pumps immediately with a different vendor model to eliminate the vulnerability', 'explanation': 'Immediate replacement of all infusion pumps is operationally impossible and unnecessary. Network isolation provides immediate protection while a sustainable remediation plan is developed with the manufacturer and FDA.', 'correct': False}], 'overall_explanation': 'Medical IoT (IoMT) incident response follows patient safety first principles: immediately implement network controls to prevent exploitation, ensure clinical operations can continue safely with manual monitoring if needed, notify clinical leadership and medical engineering, coordinate with manufacturer and FDA under medical device cybersecurity regulations, and communicate clearly with clinical staff about temporary operational changes.', 'domain': 'IoT Security - Applied Scenarios'}, {'question': 'A retail chain deploys 5000 IoT-enabled point of sale terminals. A security assessment finds the terminals are running outdated firmware with a known card data exfiltration vulnerability. What is the risk and required response under PCI DSS?', 'options': [{'text': 'PCI DSS does not apply to IoT devices only to servers and workstations processing payment data', 'explanation': 'PCI DSS applies to any system component that stores, processes, or transmits cardholder data including IoT-enabled point of sale terminals. PCI DSS scope includes all IoT devices in the cardholder data environment.', 'correct': False}, {'text': 'PCI DSS requires immediate patching or compensating controls for known vulnerabilities in cardholder data environment systems with potential for significant fines and loss of card processing capability for non-compliance', 'explanation': 'Correct. PCI DSS Requirement 6 mandates protecting systems against known vulnerabilities by installing applicable security patches. A known card data exfiltration vulnerability on 5000 POS terminals represents a critical PCI DSS compliance failure. Response: emergency patch deployment or network-level compensating controls, forensic investigation for evidence of exploitation, mandatory breach notification if card data was exposed, and notification to the acquiring bank of the vulnerability.', 'correct': True}, {'text': 'The vulnerability is low risk because IoT POS terminals are isolated from the internet reducing exploitation likelihood', 'explanation': 'Network isolation reduces but does not eliminate risk. PCI DSS requires patching known vulnerabilities regardless of network position. A known card data exfiltration vulnerability requires immediate action even in isolated environments.', 'correct': False}, {'text': 'Retailers can self-certify PCI DSS compliance for IoT terminals without any third-party assessment', 'explanation': 'PCI DSS assessment requirements depend on transaction volume. High-volume merchants require QSA (Qualified Security Assessor) assessments. Self-assessment questionnaires are only available for lower-volume merchants meeting specific criteria.', 'correct': False}], 'overall_explanation': 'PCI DSS IoT compliance: all POS terminals are in scope for cardholder data environment requirements, firmware must be kept current with security patches, network segmentation of payment devices is required, anomaly monitoring for unusual payment data patterns is required, and any suspected compromise triggers mandatory breach investigation and notification procedures.', 'domain': 'IoT Security - Applied Scenarios'}, {'question': 'A smart home security company discovers that their IoT doorbell cameras have been streaming video to an unauthorised third-party server in addition to the customer cloud platform. What privacy and security incident response is required?', 'options': [{'text': 'The company should quietly push a firmware update to stop the unauthorised streaming without notifying affected customers', 'explanation': 'Silent remediation without customer notification violates privacy breach notification requirements under GDPR, CCPA and other regulations. Customers have a right to know their home video has been shared with unauthorised parties.', 'correct': False}, {'text': 'Immediate firmware update to stop unauthorised streaming mandatory breach notification to regulators and affected customers within required timeframes forensic investigation and regulatory cooperation', 'explanation': 'Correct. Response requirements: immediately stop the unauthorised data transfer via emergency firmware update, conduct forensic investigation to determine scope and duration of exposure, notify relevant data protection authorities within 72 hours under GDPR, notify affected customers explaining what data was shared, with whom, for how long, and what remediation has been taken, cooperate with regulatory investigation, and implement systematic security testing to identify similar issues.', 'correct': True}, {'text': 'Customer notification is only required if the unauthorised server is located in the same country as the customers', 'explanation': 'Data breach notification requirements apply regardless of where the unauthorised server is located. The location of the server does not affect the customer right to know their data was shared without consent.', 'correct': False}, {'text': 'Since the cameras were functioning normally for customers the incident does not constitute a security or privacy breach requiring notification', 'explanation': 'Unauthorised streaming of home video to a third party is a clear privacy breach regardless of normal camera functionality for customers. The covert third-party data transfer was unknown to and unconsented by customers constituting a notifiable breach.', 'correct': False}], 'overall_explanation': 'IoT privacy breach response: stop the data transfer immediately, scope the breach (how many devices, what data, how long, who received it), notify data protection authorities within required timeframes (72 hours under GDPR), notify affected individuals with clear explanation and remediation steps, cooperate with regulatory investigation, implement systematic security testing of other products, and review supply chain and development processes for similar vulnerabilities.', 'domain': 'IoT Security - Applied Scenarios'}, {'question': 'A manufacturing facility deploys IIoT vibration sensors on critical machinery for predictive maintenance. The sensors connect to an edge gateway which sends data to a cloud analytics platform. An attacker compromises the edge gateway. What can they do and what is the impact?', 'options': [{'text': 'A compromised edge gateway can only read sensor data and cannot affect physical machinery or the cloud platform', 'explanation': 'An edge gateway compromise has bidirectional impact. The attacker can manipulate data sent to the cloud and may be able to send commands back to connected devices depending on the architecture.', 'correct': False}, {'text': 'A compromised edge gateway can manipulate sensor data causing false maintenance alerts disable real alerts masking genuine equipment failures and potentially pivot into the OT network if not properly isolated', 'explanation': 'Correct. Edge gateway compromise impacts: manipulating vibration data to generate false alerts causing unnecessary maintenance downtime, suppressing genuine fault alerts allowing equipment to fail catastrophically, pivoting into the OT production network if gateway has OT network connectivity, accessing all sensor data revealing operational intelligence about production processes, and potentially issuing unauthorised commands if the gateway has actuator control capability.', 'correct': True}, {'text': 'Edge gateway compromise is low impact because the attacker cannot access the cloud analytics platform from the gateway', 'explanation': 'Edge gateways have cloud connectivity by definition. A compromised gateway has the cloud platform credentials and connectivity to interact with the cloud platform potentially compromising cloud-side data and authentication.', 'correct': False}, {'text': 'The impact is limited to the single gateway and cannot affect other gateways or devices in the deployment', 'explanation': 'A compromised gateway may have credentials or network access that enables lateral movement to other gateways or devices. Cloud platform credentials on the compromised gateway may provide access to manage other gateways in the same fleet.', 'correct': False}], 'overall_explanation': 'Edge gateway security is critical because gateways have privileged positions with access to both OT sensor networks and cloud platforms. Compromise enables data manipulation affecting maintenance decisions and potentially physical equipment safety. Security requirements: network isolation of gateway from OT control network, minimal permissions on cloud platform, integrity monitoring for gateway configuration and software, and monitoring for anomalous data patterns indicating gateway manipulation.', 'domain': 'IoT Security - Applied Scenarios'}, {'question': 'An organisation discovers that a third-party IoT integration partner has been accessing their IoT platform beyond their agreed scope reading data from devices outside their authorised deployment. What governance and technical failures enabled this?', 'options': [{'text': 'Third-party IoT access violations are entirely the fault of the third party with no governance failure on the organisation side', 'explanation': 'While the third party violated their access agreement the organisation has responsibility for implementing technical controls preventing over-privileged third-party access regardless of contractual agreements.', 'correct': False}, {'text': 'Insufficient technical access controls granting broader than necessary permissions and inadequate monitoring to detect access pattern anomalies both represent governance failures enabling the violation', 'explanation': 'Correct. Governance failures enabling third-party over-access: technical controls granting access to all devices rather than the specific authorised subset, no monitoring of third-party access patterns against authorised scope, no regular access review comparing actual usage to agreed permissions, and contractual controls without technical enforcement. Both governance and technical failures contributed.', 'correct': True}, {'text': 'The only failure was insufficient contractual controls and technical access controls were not required', 'explanation': 'Contractual controls without technical enforcement are insufficient. Contracts define what is permitted but technical access controls prevent violations regardless of whether the third party honours the contract. Both are required.', 'correct': False}, {'text': 'Third-party IoT access should be completely prohibited to prevent any possibility of unauthorised access', 'explanation': 'Prohibiting all third-party IoT access is impractical as many legitimate IoT deployments require integration partners. The correct approach is properly scoped technical access controls with monitoring not prohibition of all third-party access.', 'correct': False}], 'overall_explanation': 'Third-party IoT access governance: implement technical access controls limiting each partner to their specific authorised devices and operations, monitor all third-party access patterns against authorised scope, conduct quarterly access reviews comparing actual usage to permissions, include right-to-audit clauses in integration contracts, implement alerting for access outside normal patterns, and immediately revoke access when violations are detected.', 'domain': 'IoT Security - Applied Scenarios'}, {'question': 'A city council deploys connected parking meters that accept contactless payment. A security researcher discovers the meters transmit payment card data unencrypted over WiFi. What is the severity and required response?', 'options': [{'text': 'The vulnerability is low severity because the meters are in public locations where privacy expectations are lower', 'explanation': 'Privacy expectations regarding financial data do not vary based on device location. Payment card data transmission without encryption is a critical vulnerability regardless of where the device is located.', 'correct': False}, {'text': 'This is a critical PCI DSS violation and potential mass card theft scenario requiring immediate payment function suspension forensic investigation and mandatory breach notification', 'explanation': 'Correct. Unencrypted payment card data over WiFi is a critical vulnerability enabling card data capture by anyone with WiFi equipment near the meters. Response: immediately suspend contactless payment to prevent ongoing card data theft, forensic investigation to determine if card data was captured and duration of exposure, PCI DSS breach notification to acquiring bank, potential notification to affected cardholders if card data was compromised, emergency firmware update implementing encryption, and regulatory notification as required.', 'correct': True}, {'text': 'The vulnerability only requires patching at the next scheduled maintenance window as unencrypted WiFi is common for IoT devices', 'explanation': 'Unencrypted payment card data transmission is a critical breach of PCI DSS requirements requiring immediate action not scheduled maintenance response. Every moment of continued operation risks additional card data theft.', 'correct': False}, {'text': 'The council only needs to notify the parking meter vendor and take no other action as the vendor is responsible for the security of their product', 'explanation': 'The council as the deploying organisation is responsible for PCI DSS compliance of payment systems they operate. Vendor notification is one step but the council has independent obligations for breach notification, payment suspension, and cardholder notification.', 'correct': False}], 'overall_explanation': 'IoT payment security incidents: PCI DSS applies to any system accepting card payments including parking meters. Unencrypted card data transmission is an automatic PCI DSS violation requiring immediate incident response. The organisation deploying the payment IoT devices is the merchant responsible for PCI DSS compliance regardless of the device manufacturer responsibility for the vulnerability.', 'domain': 'IoT Security - Applied Scenarios'}, {'question': 'What lessons should an IoT security manager draw from the 2021 Oldsmar Florida water treatment attack for their own IoT and OT deployment?', 'options': [{'text': 'The Oldsmar attack only demonstrates risks for water utilities and has no lessons for other IoT deployments', 'explanation': 'The Oldsmar attack demonstrates fundamental IoT and OT security principles applicable to any deployment including remote access security, monitoring, and operator vigilance that are relevant beyond water utilities.', 'correct': False}, {'text': 'Remote access tools must be properly secured with MFA operator monitoring detected the attack demonstrating the importance of human oversight and basic security hygiene prevents most attacks', 'explanation': 'Correct. Oldsmar lessons: TeamViewer was used without MFA creating the access vector demonstrating remote access must require MFA and be properly secured, an alert operator detected the cursor moving and reversed the change demonstrating operator training and vigilance as critical detective controls, and the entire attack was enabled by basic security failures (weak remote access) not sophisticated techniques demonstrating that fundamentals prevent most IoT attacks.', 'correct': True}, {'text': 'The Oldsmar attack proves that all water treatment facilities should disconnect from the internet entirely', 'explanation': 'Complete internet disconnection is operationally impractical for most water utilities and the lesson is proper security implementation of necessary connectivity not elimination of all connectivity.', 'correct': False}, {'text': 'The attack shows that operator training is the only effective security control as technology controls were bypassed', 'explanation': 'Technology controls including MFA, network segmentation, and monitoring would have prevented or detected the attack earlier. Human vigilance complemented these controls but cannot replace them. Defence-in-depth combining technology and human controls is the lesson.', 'correct': False}], 'overall_explanation': 'Oldsmar applicable lessons: implement MFA for all remote access to IoT and OT systems, train operators to recognise and respond to anomalous HMI behaviour, use purpose-built secure remote access solutions not general consumer tools like TeamViewer, implement network segmentation preventing direct internet access to control systems, and establish clear procedures for operators to report and respond to suspected cyber activity.', 'domain': 'IoT Security - Applied Scenarios'}, {'question': 'An organisation plans to deploy 1000 IoT environmental sensors in a remote national park with cellular connectivity. What security challenges are unique to this deployment context?', 'options': [{'text': 'Remote IoT deployments have no unique security challenges compared to urban deployments', 'explanation': 'Remote IoT deployments have specific challenges including physical security of unattended devices, limited connectivity for updates, difficult remediation requiring physical access, and environmental factors affecting device integrity.', 'correct': False}, {'text': 'Physical access by adversaries limited connectivity for updates difficult remote remediation and cellular network security requirements all create unique challenges for remote unattended IoT deployments', 'explanation': 'Correct. Remote national park IoT challenges: physically accessible unattended devices enabling hardware tampering and theft, limited cellular bandwidth constraining security update delivery, difficult remediation requiring physical access to remote locations for any hardware intervention, cellular network security including SIM management and cellular interception risks, power supply security (solar/battery manipulation), and environmental tampering potentially affecting sensor readings.', 'correct': True}, {'text': 'Remote IoT deployments are more secure than urban deployments because there are fewer people who could attempt to compromise the devices', 'explanation': 'Fewer people near devices does not equal better security. Remote unattended devices are more vulnerable to physical tampering precisely because they are not monitored. Security must be implemented in the device itself not relied on through population density.', 'correct': False}, {'text': 'Cellular connectivity makes remote IoT devices more secure than WiFi-connected devices as cellular is more difficult to intercept', 'explanation': 'Cellular has security advantages over WiFi for some attack vectors but introduces SIM-specific risks and does not eliminate the need for end-to-end encryption and device authentication.', 'correct': False}], 'overall_explanation': 'Remote unattended IoT security design: tamper-evident physical enclosures with tamper detection alerting, hardware security modules for credential storage, end-to-end encryption for all cellular communications, minimal cellular data usage reducing attack surface, battery and power supply monitoring detecting tampering, geofencing alerts for unexpected device location changes, and remote wipe capability for compromised devices that cannot be physically retrieved.', 'domain': 'IoT Security - Applied Scenarios'}, {'question': 'A wearable health monitoring device collects continuous heart rate blood pressure and activity data syncing to a companion app and cloud platform. What are the key security and privacy considerations?', 'options': [{'text': 'Wearable health devices only need basic password protection as health data is only sensitive if it includes medical diagnoses', 'explanation': 'Continuous biometric monitoring data (heart rate, blood pressure, activity patterns) is highly sensitive health data even without formal diagnoses. It can reveal health conditions, activity patterns, and personal behaviours creating significant privacy and security risks.', 'correct': False}, {'text': 'Health data classification as sensitive personal data under GDPR and HIPAA end-to-end encryption bluetooth security for phone sync and cloud data protection with strict access controls and minimal retention', 'explanation': 'Correct. Wearable health data security: health data is special category under GDPR requiring explicit consent and enhanced protection, HIPAA applies if the device processes health information for covered entities, Bluetooth sync must use secure pairing preventing interception of health data, cloud storage requires encryption and strict access controls, data minimisation keeping only clinically necessary data, defined retention periods with automatic deletion, and breach notification requirements are particularly strict for health data.', 'correct': True}, {'text': 'Consumer wearables are exempt from health data regulations as they are lifestyle devices not medical devices', 'explanation': 'The regulatory classification depends on the data processed and claims made not just the consumer versus medical label. Wearables processing health data and making health-related claims may be subject to medical device regulations and health data privacy laws regardless of marketing positioning.', 'correct': False}, {'text': 'Wearable health data security is entirely the responsibility of the companion app not the wearable device manufacturer', 'explanation': 'Both the wearable device manufacturer and app developer share security responsibility. The device manufacturer is responsible for secure Bluetooth communication, firmware security, and data security on the device itself.', 'correct': False}], 'overall_explanation': 'Wearable health IoT security framework: classify health data appropriately (special category GDPR, PHI under HIPAA where applicable), implement end-to-end encryption from device through app to cloud, secure Bluetooth pairing using BLE secure connections mode, strict data access controls on cloud platform, privacy by design with data minimisation, clear privacy notices and consent mechanisms, and enhanced breach notification procedures for health data incidents.', 'domain': 'IoT Security - Applied Scenarios'}, {'question': 'What is the most important single security control for an organisation just beginning its IoT security programme with minimal existing controls?', 'options': [{'text': 'Immediately deploy an expensive IoT Security Operations Centre with 24/7 monitoring as the highest priority', 'explanation': 'A SOC is a mature capability that requires foundational controls to be effective. For an organisation just beginning its IoT security journey foundational controls provide more immediate risk reduction than advanced monitoring.', 'correct': False}, {'text': 'Establish a complete IoT asset inventory as visibility into what IoT devices exist and their security status is the prerequisite for all other security controls', 'explanation': 'Correct. Without knowing what IoT devices exist you cannot protect them, patch them, monitor them, or respond to incidents involving them. An IoT asset inventory is the foundational control that enables all others. It reveals unknown devices, identifies unsupported firmware versions, maps network connectivity, and provides the baseline for vulnerability management and monitoring.', 'correct': True}, {'text': 'Purchase an IoT vulnerability scanning platform as identifying vulnerabilities is more important than knowing what devices exist', 'explanation': 'Vulnerability scanning without an asset inventory produces incomplete results. You cannot assess vulnerability exposure across your fleet if you do not have a complete inventory of what devices are in your environment.', 'correct': False}, {'text': 'Implement MFA for all IoT management access as authentication is the single highest-value first control', 'explanation': 'MFA for management access is a high-value control but cannot be systematically implemented without first knowing what management interfaces exist across your IoT fleet which requires an asset inventory.', 'correct': False}], 'overall_explanation': 'IoT security programme foundation: 1) Asset inventory (you cannot protect what you cannot see - enables all other controls), 2) Network segmentation (limits blast radius of any compromise), 3) Authentication controls (MFA for management, unique device credentials), 4) Vulnerability management (patch compliance tracking), 5) Monitoring (anomaly detection). Start with visibility then protection then detection.', 'domain': 'IoT Security - Applied Scenarios'}]